package jetbrains.mps.baseLanguage.unitTest.execution.server;

/*Generated by MPS */

import org.junit.platform.engine.DiscoverySelector;
import jetbrains.mps.baselanguage.unitTest.execution.launcher.JUnit5TestContributor;
import jetbrains.mps.project.MPSProject;
import jetbrains.mps.baseLanguage.unitTest.execution.client.ITestNodeWrapper;
import java.util.List;
import org.jetbrains.annotations.NotNull;
import org.jetbrains.mps.openapi.module.SModule;
import org.junit.platform.engine.discovery.DiscoverySelectors;
import jetbrains.mps.module.ModuleClassLoaderIsNullException;

/**
 * Adaptation of {@code NodeWrappersTestsContributor} tp JUnit5 API.
 */
public class JUnit5InprocessTestsContributor extends AbstractInProcessTestContributor<DiscoverySelector> implements JUnit5TestContributor {

  public JUnit5InprocessTestsContributor(MPSProject mpsProject, String runConfigurationName, Iterable<? extends ITestNodeWrapper> testNodes) {
    super(mpsProject, runConfigurationName, testNodes);
  }

  @Override
  public List<DiscoverySelector> collectSelectors() {
    return collect();
  }

  @NotNull
  @Override
  protected DiscoverySelector processTestCase(ITestNodeWrapper testNode, SModule testModule, String fqName) {
    try {
      return selectorForTestClass(fqName, testModule);
    } catch (ClassNotFoundException e) {
      notifyByBaloonCLNF(e, testNode);
      return createFailedTestForClass(fqName, e);
    } catch (Exception e) {
      return createFailedTestForClass(fqName, e);
    }
  }

  @NotNull
  @Override
  protected DiscoverySelector processTestMethod(ITestNodeWrapper testNode, SModule testModule, String fqName) {
    int index = fqName.lastIndexOf('.');
    String testFqName = fqName.substring(0, index);
    String methodName = fqName.substring(index + 1);
    try {
      return selectorForTestMethod(testFqName, methodName, testModule);
    } catch (ClassNotFoundException e) {
      notifyByBaloonCLNF(e, testNode);
      return createFailedTestForMethod(testFqName, methodName, e);
    } catch (Exception e) {
      return createFailedTestForMethod(testFqName, methodName, e);
    }
  }

  @Override
  @NotNull
  protected DiscoverySelector createFailedTestForClass(String fqName, Exception e) {
    return DiscoverySelectors.selectUniqueId("[class:" + fqName + "]");
  }

  @Override
  @NotNull
  protected DiscoverySelector createFailedTestForMethod(String testFqName, String methodName, Exception e) {
    return DiscoverySelectors.selectUniqueId("[class:" + testFqName + "]/[method:" + methodName + "]");
  }

  private DiscoverySelector selectorForTestMethod(String fqName, String methodName, SModule module) throws ClassNotFoundException, ModuleClassLoaderIsNullException {
    final Class<?> aClass = loadTestClass(fqName, module);
    return DiscoverySelectors.selectMethod(aClass, methodName);
  }

  private DiscoverySelector selectorForTestClass(String fqName, SModule module) throws ClassNotFoundException, ModuleClassLoaderIsNullException {
    final Class<?> aClass = loadTestClass(fqName, module);
    return DiscoverySelectors.selectClass(aClass);
  }


}
